 256→router.get('/getNotifications', requireAuth, async(req, res) =>{
 257→    const {before, limit} = req.query;
 258→    const userId = req.userId;
 259→
 260→    // Fetch a generous amount from both tables, then merge and paginate
 261→    const fetchLimit = parseInt(limit) + 1;
 262→
 263→    let journalQuery = supabase
 264→    .from('notifications')
 265→    .select(
 266→        `*,
 267→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
 268→        users!sender_id(name, user_email, image_url, id, badge),
 269→        constellation_id,
 270→        constellations!constellation_id(status, star_id_a, star_id_b)
 271→        `
 272→    )
 273→    .eq('receiver_id', userId)
 274→    .order('created_at', {ascending: false})
 275→    .order('id', {ascending: false})
 276→    .limit(fetchLimit)
 277→
 278→    let opinionQuery = supabase
 279→    .from('notification_opinions')
 280→    .select(
 281→        `*,
 282→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
 283→        users!sender_id(name, user_email, image_url, id, badge)
 284→        `
 285→    )
 286→    .eq('receiver_id', userId)
 287→    .order('created_at', {ascending: false})
 288→    .order('id', {ascending: false})
 289→    .limit(fetchLimit)
 290→
 291→    if(before){
 292→        journalQuery = journalQuery.lt('created_at', before);
 293→        opinionQuery = opinionQuery.lt('created_at', before);
 294→    }
 295→
 296→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 297→
 298→    if(journalResult.error){
 299→        console.error('error while fetching data from notification table:', journalResult.error);
 300→        return res.status(500).json({error: 'error fetching data from notification table'});
 301→    }
 302→    if(opinionResult.error){
 303→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 304→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 305→    }
 306→
 307→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 308→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 309→
 310→    // Merge and sort by created_at descending
 311→    const merged = [...journalNotifs, ...opinionNotifs]
 312→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 313→
 314→    // Likes/bookmarks lookup only for journal notifications
 315→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 316→
 317→    let hasLikedResult = [];
 318→    let hasBookMarkedResult = [];
 319→    if(journalIds.length > 0){
 320→        const [hasLiked, hasBookMarked] = await Promise.all([
 321→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 322→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 323→        ]);
 324→
 325→        if(hasLiked.error || hasBookMarked.error){
 326→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 327→        }
 328→        hasLikedResult = hasLiked.data || [];
 329→        hasBookMarkedResult = hasBookMarked.data || [];
 330→    }
 331→
 332→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 333→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 334→
 335→    const formatted = merged.map((notif) => ({
 336→        ...notif,
 337→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 338→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 339→    }))
 340→
 341→    const hasMore = formatted.length > parseInt(limit);
 342→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
 343→
 344→    return res.status(200).json(
 345→        {
 346→            hasMore: hasMore,
 347→            data: slicedData,
 348→        }
 349→    )
 350→
 351→})
