 311→        }
 312→    }
 313→
 314→    const parsedDate = Date.parse(item?.created_at || item?.updated_at || '');
 315→    return Number.isNaN(parsedDate) ? 0 : parsedDate;
 316→};
 317→
 318→const createInitialMediaCursorState = () => ({
 319→    offsets: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, 0])),
 320→    exhausted: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, false])),
 321→    pending: []
 322→});
 323→
 324→const parseMediaCursor = (cursor) => {
 325→    if(!cursor){
 326→        return createInitialMediaCursorState();
 327→    }
 328→
 329→    try {
 330→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
 331→        const parsed = JSON.parse(decoded);
 332→        const initial = createInitialMediaCursorState();
 333→
 334→        if(parsed?.offsets && typeof parsed.offsets === 'object'){
 335→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
 336→                const value = Number(parsed.offsets[bucket]);
 337→                initial.offsets[bucket] = Number.isNaN(value) || value < 0 ? 0 : value;
 338→            });
 339→        }
 340→
 341→        if(parsed?.exhausted && typeof parsed.exhausted === 'object'){
 342→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
 343→                initial.exhausted[bucket] = Boolean(parsed.exhausted[bucket]);
 344→            });
 345→        }
 346→
 347→        if(Array.isArray(parsed?.pending)){
 348→            initial.pending = parsed.pending
 349→                .filter((item) => PROFILE_MEDIA_BUCKETS.includes(item?.bucket) && typeof item?.path === 'string' && typeof item?.name === 'string')
 350→                .map((item) => ({
 351→                    bucket: item.bucket,
 352→                    path: item.path,
 353→                    name: item.name,
 354→                    createdAt: item.createdAt || null,
 355→                    timestamp: Number(item.timestamp) || 0
 356→                }));
 357→        }
 358→
 359→        return initial;
 360→    } catch {
 361→        return createInitialMediaCursorState();
 362→    }
 363→};
 364→
 365→const encodeMediaCursor = (state) => {
 366→    const payload = JSON.stringify(state);
 367→    return Buffer.from(payload, 'utf8').toString('base64');
 368→};
 369→
 370→const parseCanvasGalleryCursor = (cursor, expectedSort = 'hottest') => {
 371→    const fallback = {
 372→        offset: 0,
 373→        sort: expectedSort
 374→    };
 375→
 376→    if(!cursor){
 377→        return fallback;
 378→    }
 379→
 380→    try {
 381→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
 382→        const parsed = JSON.parse(decoded);
 383→        const parsedSort = typeof parsed?.sort === 'string' && parsed.sort.toLowerCase().trim() === 'newest'
 384→            ? 'newest'
 385→            : 'hottest';
 386→
 387→        if(parsedSort !== expectedSort){
 388→            return fallback;
 389→        }
 390→
 391→        const parsedOffset = Number(parsed?.offset);
 392→        const normalizedOffset = Number.isNaN(parsedOffset) || parsedOffset < 0
 393→            ? 0
 394→            : Math.floor(parsedOffset);
 395→
 396→        return {
 397→            offset: normalizedOffset,
 398→            sort: parsedSort
 399→        };
 400→    } catch {
 401→        return fallback;
 402→    }
 403→};
