 405→const encodeCanvasGalleryCursor = (offset, sort) => {
 406→    const payload = JSON.stringify({
 407→        offset: offset,
 408→        sort: sort
 409→    });
 410→    return Buffer.from(payload, 'utf8').toString('base64');
 411→};
