 636→export const getJournalsService = async(limit, userId, before) => {
 637→    if(isNaN(limit) || limit > 20 || limit < 1){
 638→        console.error('limit should be intiger, not below 1 and higher than 20');
 639→        throw {status: 400, error: 'limit should be intiger, not below 1 and higher than 20'};
 640→    }
 641→
 642→    const parsedLimit = parseInt(limit);
 643→
 644→    let query = supabase
 645→    .from('journals')
 646→    .select(`
 647→        *, users(*),
 648→        like_count: likes(count),
 649→        comment_count: comments(count),
 650→        bookmark_count: bookmarks(count)
 651→        `)
 652→    .eq('privacy', 'public')
 653→    .order('created_at', {ascending: false})
 654→    .order('id', {ascending: false})
 655→    .limit(parsedLimit + 1);
 656→
 657→    if(before){
 658→        query = query.lt('created_at', before);
 659→    }
 660→
 661→    const {data, error} = await query;
 662→
 663→    if(error){
 664→        console.error('supabase error while fetching journals:', error.message);
 665→        throw{status: 500, error: 'supabase error while fetching journals'}
 666→    }
 667→
 668→    if(data.length === 0){
 669→        const journalData = {
 670→            data: [],
 671→            hasMore: false
 672→        }
 673→        return journalData
 674→    }
 675→
 676→    // If userId is provided, fetch personalization (likes/bookmarks)
 677→    // Otherwise return journals with has_liked/has_bookmarked defaulting to false
 678→    let userHasLikedSet = new Set();
 679→    let userHasBookmarkedSet = new Set();
 680→
 681→    if(userId){
 682→        const journalIds = data.map((journal) => journal.id);
 683→
 684→        const [userLikes, userBookmarks] = await Promise.all([
 685→            supabase
 686→            .from('likes')
 687→            .select('journal_id')
 688→            .in('journal_id', journalIds)
 689→            .eq('user_id', userId),
 690→
 691→            supabase
 692→            .from('bookmarks')
 693→            .select('journal_id')
 694→            .in('journal_id', journalIds)
 695→            .eq('user_id', userId)
 696→        ]);
 697→
 698→        const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
 699→        const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
 700→
 701→        if(errorUserLikeResult || errorUserBookmarksResult) {
 702→            console.error('supabase error:', errorUserLikeResult?.message || errorUserBookmarksResult?.message);
 703→            throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'}
 704→        }
 705→
 706→        userHasLikedSet = new Set(userLikesResult?.map((j) => j.journal_id) || []);
 707→        userHasBookmarkedSet = new Set(userBookmarksResult?.map((j) => j.journal_id)|| []);
 708→    }
 709→
 710→    await attachRepostSources(data);
 711→
 712→    const formattedData = data?.map((journal) => ({
 713→        ...journal,
 714→        has_liked: userHasLikedSet.has(journal.id),
 715→        has_bookmarked: userHasBookmarkedSet.has(journal.id)
 716→    }))
 717→
 718→    const hasMore = data?.length > parsedLimit;
 719→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
 720→
 721→    const journalData = {
 722→        data: slicedData,
 723→        hasMore: hasMore
 724→    }
 725→    return journalData;
 726→}
