 728→export const getMonthlyHottestJournalsService = async(limit, userId) => {
 729→    if(isNaN(limit) || limit < 1 || limit > 10){
 730→        throw {status: 400, error: 'limit should be an integer between 1 and 10'};
 731→    }
 732→
 733→    const parsedLimit = parseInt(limit);
 734→    const now = new Date();
 735→    const monthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0, 0));
 736→    const nextMonthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0, 0));
 737→
 738→    const {data: journals, error: journalsError} = await supabase
 739→        .from('journals')
 740→        .select(`
 741→            *,
 742→            users(*),
 743→            like_count: likes(count),
 744→            comment_count: comments(count),
 745→            bookmark_count: bookmarks(count)
 746→        `)
 747→        .eq('privacy', 'public')
 748→        .gte('created_at', monthStartUtc.toISOString())
 749→        .lt('created_at', nextMonthStartUtc.toISOString());
 750→
 751→    if(journalsError){
 752→        console.error('supabase error while fetching monthly hottest journals:', journalsError.message);
 753→        throw {status: 500, error: 'supabase error while fetching monthly hottest journals'};
 754→    }
 755→
 756→    const journalsWithInteractions = await attachUserInteractionFlags(journals || [], userId);
 757→    const scored = journalsWithInteractions.map((journal) => {
 758→        const likes = journal?.like_count?.[0]?.count || 0;
 759→        const comments = journal?.comment_count?.[0]?.count || 0;
 760→        const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 761→        const views = journal?.views || 0;
 762→        const hotScore = (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
 763→
 764→        return {
 765→            ...journal,
 766→            hot_score: hotScore
 767→        };
 768→    });
 769→
 770→    scored.sort((a, b) => {
 771→        const scoreDiff = (b?.hot_score || 0) - (a?.hot_score || 0);
 772→        if(scoreDiff !== 0){
 773→            return scoreDiff;
 774→        }
 775→
 776→        const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 777→        if(dateDiff !== 0){
 778→            return dateDiff;
 779→        }
 780→
 781→        return (b?.id || 0) - (a?.id || 0);
 782→    });
 783→
 784→    return {
 785→        data: scored.slice(0, parsedLimit),
 786→        period: {
 787→            startUtc: monthStartUtc.toISOString(),
 788→            endUtc: nextMonthStartUtc.toISOString(),
 789→            timezone: 'UTC'
 790→        },
 791→        totalCandidates: scored.length
 792→    };
 793→}
