11→export const handleCLickContent = (navigate) => {
12→    return (
13→        e,
14→        jsonbContent,
15→        wholeText,
16→        title,
17→        userId,
18→        name,
19→        avatar,
20→        created_at,
21→        journalId,
22→        isLiked,
23→        commentsCount,
24→        isBookmarked,
25→        likesCount,
26→        bookmarksCount,
27→        badge,
28→        postType = null,
29→        canvasDoc = null
30→    ) => {
31→    e.stopPropagation()
32→
33→    const encodedJournalId = journalId ? encodeURIComponent(journalId) : '';
34→    const postSlug = slugifyTitle(title);
35→    const nextPath = journalId
36→        ? `/home/post/${encodedJournalId}${postSlug ? `/${postSlug}` : ''}`
37→        : '/home/contentViewer';
38→
39→    navigate(nextPath, {
40→        state: {
41→            content: jsonbContent,
42→            wholeText: wholeText,
43→            title: title,
44→            userId: userId,
45→            name: name,
46→            avatar: avatar,
47→            created_at: created_at,
48→            journalId: journalId,
49→            isLiked: isLiked, 
50→            commentsCount: commentsCount,
51→            isBookmarked: isBookmarked,
52→            likesCount: likesCount,
53→            bookmarksCount: bookmarksCount,
54→            badge: badge,
55→            postType: postType,
56→            canvasDoc: canvasDoc
57→        }
58→    })
59→    }
60→    
61→}
