 17→const getHotScore = (journal) => {
 18→    if(typeof journal?.hot_score === "number"){
 19→        return journal.hot_score;
 20→    }
 21→
 22→    const likes = journal?.like_count?.[0]?.count || 0;
 23→    const comments = journal?.comment_count?.[0]?.count || 0;
 24→    const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 25→    const views = journal?.views || 0;
 26→
 27→    return (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
 28→};
