184→const ExplorePage = () => {
185→    const navigate = useNavigate();
186→    const { session, user, openAuthModal } = useAuth();
187→    const userId = user?.userData?.[0]?.id || null;
188→    const mutateViews = useAddViewsMutation(session);
189→    const searchShellRef = useRef(null);
190→
191→    const [searchInput, setSearchInput] = useState("");
192→    const [debouncedSearchInput, setDebouncedSearchInput] = useState("");
193→    const [committedSearchQuery, setCommittedSearchQuery] = useState("");
194→    const [isSearchFocused, setIsSearchFocused] = useState(false);
195→    const currentUtcMonthKey = `${new Date().getUTCFullYear()}-${String(new Date().getUTCMonth() + 1).padStart(2, "0")}`;
196→
197→    useEffect(() => {
198→        const timer = setTimeout(() => {
199→            setDebouncedSearchInput(searchInput.trim());
200→        }, 350);
201→
202→        return () => clearTimeout(timer);
203→    }, [searchInput]);
204→
205→    const isSearchMode = committedSearchQuery.length >= 2;
206→
207→    const { data: feedData, isLoading: isLoadingFeed } = useQuery({
208→        queryKey: ["explore-hottest-monthly-feed", userId, currentUtcMonthKey],
209→        queryFn: () => getMonthlyHottestJournals(userId, 10),
210→        refetchOnWindowFocus: false,
211→        staleTime: 15 * 1000,
212→    });
213→
214→    const {
215→        data: searchData,
216→        isLoading: isLoadingSearch,
217→        isFetching: isFetchingSearch,
218→        error: searchError,
219→    } = useQuery({
220→        queryKey: ["explore-search", userId, committedSearchQuery],
221→        queryFn: () => searchJournals(committedSearchQuery, 10, userId),
222→        enabled: isSearchMode,
223→        refetchOnWindowFocus: false,
224→        staleTime: 10 * 1000,
225→    });
226→
227→    const {
228→        data: suggestionData,
229→        isLoading: isSuggestionsLoading,
230→    } = useQuery({
231→        queryKey: ["explore-suggestions", userId, debouncedSearchInput],
232→        queryFn: () => searchJournals(debouncedSearchInput, 6, userId),
233→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused,
234→        refetchOnWindowFocus: false,
235→        staleTime: 10 * 1000,
236→    });
237→
238→    const journals = isSearchMode ? (searchData?.data || []) : (feedData?.data || []);
239→    const isLoading = isSearchMode ? isLoadingSearch : isLoadingFeed;
240→    const suggestionItems = suggestionData?.data || [];
241→    const showSuggestions = isSearchFocused && debouncedSearchInput.length >= 2;
242→
243→    const handleSubmitSearch = (rawQuery) => {
244→        const normalizedQuery = typeof rawQuery === "string" ? rawQuery.trim() : "";
245→        if(normalizedQuery.length < 2){
246→            setCommittedSearchQuery("");
247→            return;
248→        }
249→
250→        setCommittedSearchQuery(normalizedQuery);
251→        setSearchInput(normalizedQuery);
252→        setIsSearchFocused(false);
253→    };
254→
255→    const handleClearSearch = () => {
256→        setSearchInput("");
257→        setDebouncedSearchInput("");
258→        setCommittedSearchQuery("");
259→        setIsSearchFocused(false);
260→    };
261→
262→    const handleSearchInputKeyDown = (e) => {
263→        if(e.key === "Enter"){
264→            e.preventDefault();
265→            handleSubmitSearch(searchInput);
266→        }
267→
268→        if(e.key === "Escape"){
269→            setIsSearchFocused(false);
270→        }
271→    };
272→
273→    const handleClickSuggestion = (journal) => {
274→        if(!journal?.id){
275→            return;
276→        }
277→        if(!session){
278→            openAuthModal();
279→            return;
280→        }
281→        setIsSearchFocused(false);
