285→        }
286→        const formadata = new FormData();
287→        formadata.append('journalId', journal.id);
288→        mutateViews.mutate(formadata);
289→        navigate(`/home/post/${journal.id}`);
290→    };
291→
292→    const handleClickPost = (journalId) => {
293→        if(!journalId){
294→            return;
295→        }
296→        if(!session){
297→            openAuthModal();
298→            return;
299→        }
300→        const formadata = new FormData();
